import{_ as i,o as s,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"95. Clinical Supervision Of Psychologists","description":"","frontmatter":{"title":"95. Clinical Supervision Of Psychologists","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["employment","clinical-supervision","classifications"]},"headers":[],"relativePath":"ebas/mspp/clinical-supervision/95-clinical-supervision-of-psychologists.md","filePath":"ebas/mspp/clinical-supervision/95-clinical-supervision-of-psychologists.md"}'),t={name:"ebas/mspp/clinical-supervision/95-clinical-supervision-of-psychologists.md"};function a(n,e,p,l,h,c){return s(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_95-clinical-supervision-of-psychologists" tabindex="-1">95. Clinical Supervision Of Psychologists <a class="header-anchor" href="#_95-clinical-supervision-of-psychologists" aria-label="Permalink to &quot;95. Clinical Supervision Of Psychologists&quot;">​</a></h1><p><strong>a.</strong> Grade 1 and Grade 2 Psychologists will be provided with individual fortnightly clinical supervision from a psychologist classified as Grade 3 and above.</p><p><strong>b.</strong> Grade 3, Grade 4, Grade 5 and Grade 6 Psychologists will be provided with a minimum of 10 hours of individual clinical supervision per annum plus an additional 12 hours per annum peer supervision, as defined by the PBA.</p><p><strong>c.</strong> A psychologist who is employed part time will be provided with pro-rata supervision, as per their EFT fraction.</p><p><strong>d.</strong> A Psychologist Grade 3 shall be provided with regular professional supervision by a Psychologist Grade 4 or above. Where there is no Psychologist Grade 4 or above employed in the service, external supervision shall be provided.</p><p><strong>e.</strong> Individual clinical supervision will be provided in person by a more senior psychologist employed in the same clinical service. Where there are difficulties in providing face to face supervision to Psychologists Grades 4 and 5, alternative options for supervision will be offered and agreed with the psychologist, the Employer and the proposed supervisor, consistent with PBA guidelines.</p><p><strong>f.</strong> The Employer shall support the Grade 6 psychologist to seek external supervision from another Senior Psychologist. This support includes payment for supervision and time to attend supervision. External supervision arrangements will be agreed between the psychologist, the employer and the proposed supervisor.</p><p><strong>g.</strong> Supervision will be provided by a PBA approved supervisor who has a skill set appropriate to the needs of the supervisee and their role, provided that a supervisor who located outside Australia shall not be required to be a PBA approved supervisor.</p><p><strong>h.</strong> It is preferred, where possible, that the supervisor is not the line manager of the psychologist. In smaller services where there is limited capacity to provide supervision by senior psychologists employed by the employer, apart from the line manager, alternatives for supervision will be explored and negotiated with the psychologist, the employer and the proposed supervisor, consistent with PBA guidelines. The psychologist may agree for the clinical supervision to be provided by the line manager. Where there is not agreement and the psychologist believes that there may be difficulties if they are supervised by their manager, subclause 95k of this clause will apply.</p><p><strong>i.</strong> Where the PBA minimum requirements for individual clinical supervision exceed the hours set out above, for example supervision of Psychologists</p><p>Grade 1 who are employed outside University placements with PBA approval, Grade 1 Interns or Grade 2 Registrars, the employer will provide sufficient supervision to meet the PBA requirements.</p><p><strong>j.</strong> Where the individual supervision of a Psychologist Grade 3 and above cannot be provided by a supervisor with the appropriate skill set at the same worksite, or employed in the same clinical service, the employer shall provide and pay for external supervision. External supervision arrangements will be agreed between the psychologist, the employer and the proposed supervisor.</p><p><strong>k.</strong> It is recognised that there may be difficulties between a psychologist and their proposed clinical supervisor which may impair the supervisory relationship, or that such difficulties may develop. In such instances the psychologist may request a change of supervisor, which will be agreed between the psychologist, the employer and the proposed supervisor.</p><p>Plain language terms: clinical supervision, psych supervision.</p>',14)])])}const v=i(t,[["render",a]]);export{u as __pageData,v as default};
